void test_append_range()
{
    fmt::println("=== Testing append_range() ===");
    {
        // Append from span
        fixed_vector<int, 10> v({1, 2, 3});
        std::array<int, 3> arr = {4, 5, 6};
        v.append_range(std::span<const int>(arr));
        assert(v.size() == 6);
        fmt::println("After append_range(span): {}", v.span());
    }
    {
        // Append from iterators
        fixed_vector<int, 10> v({1, 2});
        std::vector<int> src = {3, 4, 5};
        v.append_range(src.begin(), src.end());
        assert(v.size() == 5);
        fmt::println("After append_range(iterators): {}", v.span());
    }
    {
        // Append from iterator + count
        fixed_vector<int, 10> v({1, 2});
        std::vector<int> src = {10, 20, 30, 40};
        v.append_range(src.begin(), 3);
        assert(v.size() == 5);
        fmt::println("After append_range(iterator, count): {}", v.span());
    }
    {
        // Append from initializer list
        fixed_vector<int, 10> v({1, 2});
        v.append_range({3, 4, 5});
        assert(v.size() == 5);
        fmt::println("After append_range(init_list): {}", v.span());
    }
    {
        // Append from range
        fixed_vector<int, 10> v({1, 2});
        std::vector<int> src = {3, 4, 5};
        v.append_range(src);
        assert(v.size() == 5);
        fmt::println("After append_range(range): {}", v.span());
    }
    {
        // Failure case - exceeds capacity
        fixed_vector<int, 10> v({1, 2, 3, 4, 5});
        std::array<int, 10> arr{};
        try {
            v.append_range(std::span<const int>(arr));
            assert(false && "Should have thrown");
        } catch (const std::bad_alloc&) {
            fmt::println("append_range() correctly threw when exceeding capacity");
        }
    }
    fmt::println("");
}

