void test_accessors()
{
    fmt::println("=== Testing Accessors ===");
    {
        fixed_vector<int, 10> v({10, 20, 30, 40, 50});

        // span()
        auto s = v.span();
        assert(s.size() == 5);
        fmt::println("span(): {}", s);

        // operator std::span
        std::span<int> s2 = static_cast<std::span<int>>(v);
        assert(s2.size() == 5);

        // data()
        assert(v.data() != nullptr);
        fmt::println("data()[0]: {}", v.data()[0]);

        // front()
        assert(v.front() == 10);
        fmt::println("front(): {}", v.front());

        v.front()++;
        assert(v.front() == 10+1);
        fmt::println("front(): {}", v.front());

        // back()
        assert(v.back() == 50);
        fmt::println("back(): {}", v.back());

        v.back()++;
        assert(v.back() == 50+1);
        fmt::println("back(): {}", v.back());

        // operator[]
        assert(v[2] == 30);
        fmt::println("operator[2]: {}", v[2]);

        // at()
        assert(v.at(3) == 40);
        fmt::println("at(3): {}", v.at(3));
    }
    {
        // at() out of range
        fixed_vector<int, 10> v({1, 2, 3});
        try {
            [[maybe_unused]] int x = v.at(5);
            assert(false && "Should have thrown");
        } catch (const std::out_of_range&) {
            fmt::println("at() correctly threw out_of_range");
        }
    }
    fmt::println("");
}

void test_iterators()
{
    fmt::println("=== Testing Iterators ===");
    {
        fixed_vector<int, 10> v({1, 2, 3, 4, 5});

        // Forward iteration
        fmt::print("Forward: ");
        for (auto it = v.begin(); it != v.end(); ++it) {
            fmt::print("{} ", *it);
        }
        fmt::println("");

        // Const iteration
        const auto& cv = v;
        fmt::print("Const: ");
        for (auto it = cv.begin(); it != cv.end(); ++it) {
            fmt::print("{} ", *it);
        }
        fmt::println("");

        // cbegin/cend
        fmt::print("cbegin/cend: ");
        for (auto it = v.cbegin(); it != v.cend(); ++it) {
            fmt::print("{} ", *it);
        }
        fmt::println("");

        // Reverse iteration
        fmt::print("Reverse: ");
        for (auto it = v.rbegin(); it != v.rend(); ++it) {
            fmt::print("{} ", *it);
        }
        fmt::println("");

        // crbegin/crend
        fmt::print("crbegin/crend: ");
        for (auto it = v.crbegin(); it != v.crend(); ++it) {
            fmt::print("{} ", *it);
        }
        fmt::println("");

        // Range-based for loop
        fmt::print("Range-based: ");
        for (int x : v) {
            fmt::print("{} ", x);
        }
        fmt::println("");
    }
    fmt::println("");
}

void test_comparison_operators()
{
    fmt::println("=== Testing Comparison Operators ===");
    {
        fixed_vector<int, 10> v1({1, 2, 3});
        fixed_vector<int, 10> v2({1, 2, 3});
        fixed_vector<int, 10> v3({1, 2, 4});
        fixed_vector<int, 10> v4({1, 2});

        // operator==
        assert(v1 == v2);
        assert(!(v1 == v3));
        assert(!(v1 == v4));
        fmt::println("v1 == v2: {}", v1 == v2);
        fmt::println("v1 == v3: {}", v1 == v3);

        // operator!=
        assert(v1 != v3);
        assert(v1 != v4);
        fmt::println("v1 != v3: {}", v1 != v3);

        // operator<=>
        assert(v1 < v3);
        assert(v3 > v1);
        assert(v4 < v1);
        fmt::println("v1 < v3: {}", v1 < v3);
        fmt::println("v3 > v1: {}", v3 > v1);
        fmt::println("v4 < v1: {}", v4 < v1);
    }
    fmt::println("");
}

