void test_algorithm_compatibility()
{
    fmt::println("=== Testing Algorithm Compatibility ===");
    {
        fixed_vector<int, 10> v({5, 2, 8, 1, 9, 3});

        // std::sort
        std::sort(v.begin(), v.end());
        fmt::println("After sort: {}", v.span());

        // std::find
        auto it = std::find(v.begin(), v.end(), 8);
        assert(it != v.end());
        fmt::println("Found 8 at position: {}", std::distance(v.begin(), it));

        // std::accumulate
        int sum = std::accumulate(v.begin(), v.end(), 0);
        fmt::println("Sum: {}", sum);

        // std::transform
        fixed_vector<int, 10> v2(6);
        std::transform(v.begin(), v.end(), v2.begin(), [](int x) { return x * 2; });
        fmt::println("After transform (*2): {}", v2.span());
    }
    fmt::println("");
}

void test_edge_cases()
{
    fmt::println("=== Testing Edge Cases ===");
    {
        // Empty vector operations
        fixed_vector<int, 10> v;
        assert(v.is_empty());
        assert(v.size() == 0);
        v.clear();  // Should be safe
        v.pop_back();  // Should be safe
        fmt::println("Empty vector operations are safe");
    }
    {
        // Full vector
        fixed_vector<int, 5> v({1, 2, 3, 4, 5});
        assert(v.is_full());
        assert(v.remaining_space() == 0);
        fmt::println("Full vector: {}", v.span());
    }
    {
        // Single element capacity
        fixed_vector<int, 1> v;
        v.push_back(42);
        assert(v.is_full());
        assert(v.size() == 1);
        fmt::println("Single element capacity: {}", v.span());
    }
    fmt::println("");
}

int main()
{
    fmt::println("====================================");
    fmt::println("Fixed Vector Comprehensive Test Suite");
    fmt::println("====================================");
    fmt::println("");

    test_default_constructor();
    test_count_constructor();
    test_count_value_constructor();
    test_span_constructor();
    test_iterator_constructor();
    test_iterator_count_constructor();
    test_initializer_list_constructor();
    test_range_constructor();
    test_copy_constructor();
    test_move_constructor();

    test_copy_assignment();
    test_move_assignment();
    test_initializer_list_assignment();

    test_size_queries();
    test_clear();
    test_resize();
    test_pop_back();
    test_emplace_back();
    test_try_emplace_back();
    test_push_back();
    test_try_push_back();
    test_unchecked_operations();
    test_fill_capacity();
    test_fill_size();
    test_append_range();
    test_try_append_range();
    test_assign_range();

    test_accessors();
    test_iterators();
    test_comparison_operators();
    test_const_correctness();
    test_algorithm_compatibility();
    test_edge_cases();

    fmt::println("====================================");
    fmt::println("All tests passed!");
    fmt::println("====================================");

    return 0;
}

